INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, critere, base_legale, objet, explications, is_custom, actif) VALUES ('dd000000-0000-4000-a000-0000dd000000', NULL, 'aa000000-0000-4000-a000-00002e000000', 'bb000000-0000-4000-a000-0000b8000000', 'S''assurer que la tour n''est pas surchargée.', 'Le personnel doit connaître la charge utile maximale figurant dans la notice.', 'Suva 67150 — Poids max', 'Charge utile', 'Le personnel doit connaître la charge utile maximale figurant dans la notice.', false, true);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, critere, base_legale, objet, explications, is_custom, actif) VALUES ('dd000000-0000-4000-a000-0000de000000', NULL, 'aa000000-0000-4000-a000-00002e000000', 'bb000000-0000-4000-a000-0000b9000000', 'Contrôler la stabilité et les roues des tours mobiles.', 'Hauteur max du fabricant. Déplacement interdit si un humain est dessus', 'OTConst — Art. 65', 'Échafaudages roulants', 'Hauteur max du fabricant. Déplacement interdit si un humain est dessus', false, true);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, critere, base_legale, objet, explications, is_custom, actif) VALUES ('dd000000-0000-4000-a000-0000df000000', NULL, 'aa000000-0000-4000-a000-00002e000000', 'bb000000-0000-4000-a000-0000b9000000', 'Vérifier la hauteur et l''utilisation des échafaudages roulants.', 'La hauteur maximale est de 8 m à l''extérieur et de 12 m à l''intérieur. L''échafaudage ne doit être déplacé que si aucune personne ne se trouve dessus et les roues doivent être bloquées en usage.', 'Suva 67150 — Fiche 67150', 'Échafaudages roulants', 'La hauteur maximale est de 8 m à l''extérieur et de 12 m à l''intérieur. L''échafaudage ne doit être déplacé que si aucune personne ne se trouve dessus et les roues doivent être bloquées en usage.', false, true);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, critere, base_legale, objet, explications, is_custom, actif) VALUES ('dd000000-0000-4000-a000-0000e0000000', NULL, 'aa000000-0000-4000-a000-00002e000000', 'bb000000-0000-4000-a000-0000ba000000', 'S''assurer que l''échafaudage ne roule pas.', 'Seules des roues bloquées évitent un déplacement involontaire du système', 'Suva 67150 — Sécurité base', 'Freins de roues', 'Seules des roues bloquées évitent un déplacement involontaire du système', false, true);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, critere, base_legale, objet, explications, is_custom, actif) VALUES ('dd000000-0000-4000-a000-0000e1000000', NULL, 'aa000000-0000-4000-a000-00002e000000', 'bb000000-0000-4000-a000-0000bb000000', 'Mesurer la hauteur de la tour roulante.', 'La hauteur maximale est de 8 m à l''extérieur et 12 m à l''intérieur.', 'Suva 67150 — Limites', 'Hauteur max', 'La hauteur maximale est de 8 m à l''extérieur et 12 m à l''intérieur.', false, true);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, critere, base_legale, objet, explications, is_custom, actif) VALUES ('dd000000-0000-4000-a000-0000e2000000', NULL, 'aa000000-0000-4000-a000-00002e000000', 'bb000000-0000-4000-a000-0000bc000000', 'Vérifier qui inspecte ce matériel volant.', 'Un responsable doit contrôler régulièrement l''état des échafaudages roulants', 'Suva 67150 — Contrôle', 'Inspection de la tour', 'Un responsable doit contrôler régulièrement l''état des échafaudages roulants', false, true);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, critere, base_legale, objet, explications, is_custom, actif) VALUES ('dd000000-0000-4000-a000-0000e3000000', NULL, 'aa000000-0000-4000-a000-00002e000000', 'bb000000-0000-4000-a000-0000bd000000', 'Vérifier par où l''ouvrier grimpe.', 'Il faut utiliser uniquement les moyens d''accès prévus à l''intérieur du cadre', 'Suva 67150 — Accès', 'Montée sur tour', 'Il faut utiliser uniquement les moyens d''accès prévus à l''intérieur du cadre', false, true);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, critere, base_legale, objet, explications, is_custom, actif) VALUES ('dd000000-0000-4000-a000-0000e4000000', NULL, 'aa000000-0000-4000-a000-00002e000000', 'bb000000-0000-4000-a000-0000be000000', 'Contrôler que les roues ne s''enfoncent pas dans la terre.', 'L''échafaudage doit reposer sur un support ferme et résistant', 'Suva 67150 — Stabilité sol', 'Plaques de répartition', 'L''échafaudage doit reposer sur un support ferme et résistant', false, true);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, critere, base_legale, objet, explications, is_custom, actif) VALUES ('dd000000-0000-4000-a000-0000e5000000', NULL, 'aa000000-0000-4000-a000-00002e000000', 'bb000000-0000-4000-a000-0000bf000000', 'Vérifier si quelqu''un est dessus pendant qu''on le pousse.', 'L''échafaudage roulant est déplacé sans aucune personne dessus', 'Suva 67150 — Mouvement', 'Présence humaine', 'L''échafaudage roulant est déplacé sans aucune personne dessus', false, true);
