INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, critere, base_legale, objet, explications, is_custom, actif) VALUES ('dd000000-0001-4000-a000-000112000000', NULL, 'aa000000-0000-4000-a000-000033000000', 'bb000000-0000-4000-a000-0000ec000000', 'Contrôler les fils qui pendent du plafond/mur brut.', 'Doivent être isolés avec des gaines thermo-rétractables ou des bornes plastiques sécurisées.', 'Suva 67081 — Attentes mur', 'Câbles qui dépassent', 'Doivent être isolés avec des gaines thermo-rétractables ou des bornes plastiques sécurisées.', false, true);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, critere, base_legale, objet, explications, is_custom, actif) VALUES ('dd000000-0001-4000-a000-000113000000', NULL, 'aa000000-0000-4000-a000-000033000000', 'bb000000-0000-4000-a000-0000ed000000', 'Vérifier que les boîtiers électriques ne sont pas cassés.', 'Toutes les parties conductrices de tension (prises, interrupteurs) doivent être fermées.', 'Suva 67081 — Contacts apparents', 'Couvercles intacts', 'Toutes les parties conductrices de tension (prises, interrupteurs) doivent être fermées.', false, true);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, critere, base_legale, objet, explications, is_custom, actif) VALUES ('dd000000-0001-4000-a000-000114000000', NULL, 'aa000000-0000-4000-a000-000033000000', 'bb000000-0000-4000-a000-0000ee000000', 'Regarder le coffret électrique rouge/noir de chantier.', 'Un Dispositif Différentiel Résiduel (DDR de 30mA) est obligatoire pour protéger la vie humaine.', 'Suva 67081 — Sécurité différentielle', 'FI/DDR', 'Un Dispositif Différentiel Résiduel (DDR de 30mA) est obligatoire pour protéger la vie humaine.', false, true);
