INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, critere, base_legale, objet, explications, is_custom, actif) VALUES ('dd000000-0001-4000-a000-000117000000', NULL, 'aa000000-0000-4000-a000-000033000000', 'bb000000-0000-4000-a000-0000f1000000', 'S''assurer qu''aucun fil caché ne traverse la zone de percement.', 'Consulter les plans et utiliser des détecteurs avant de fraiser les murs [144].', 'Suva 67081 — Forage murs', 'Risques de perçage', 'Consulter les plans et utiliser des détecteurs avant de fraiser les murs [144].', false, true);
