INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, critere, base_legale, objet, explications, is_custom, actif) VALUES ('dd000000-0001-4000-a000-000119000000', NULL, 'aa000000-0000-4000-a000-000033000000', 'bb000000-0000-4000-a000-0000f3000000', 'Vérifier la conformité des branchements et rallonges.', 'Les machines triphasées doivent avoir des prises CEE à 5 pôles (rouges). Un Dispositif Différentiel Résiduel (DDR) est obligatoire et les câbles ne doivent pas être rafistolés au scotch', 'Suva 67081 — Fiche 67081', 'Tableaux et câbles électriques', 'Les machines triphasées doivent avoir des prises CEE à 5 pôles (rouges). Un Dispositif Différentiel Résiduel (DDR) est obligatoire et les câbles ne doivent pas être rafistolés au scotch', false, true);
