INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, critere, base_legale, objet, explications, is_custom, actif) VALUES ('dd000000-0001-4000-a000-00019a000000', NULL, 'aa000000-0000-4000-a000-000055000000', 'bb000000-0001-4000-a000-000174000000', 'Vérifier l''espace libre, la mise en girouette et les autorisations de hauteur', '8 m libre au-dessus de la route. Giration libre sans charge à l''arrêt. Accord OFAC si grue > 60m ou > 25m près d''aérodrome', 'RPAC — Art. 26', 'Règles Grues (Survol)', '8 m libre au-dessus de la route. Giration libre sans charge à l''arrêt. Accord OFAC si grue > 60m ou > 25m près d''aérodrome', false, true);
