INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, critere, base_legale, objet, explications, is_custom, actif) VALUES ('dd000000-0001-4000-a000-00019c000000', NULL, 'aa000000-0000-4000-a000-000056000000', 'bb000000-0001-4000-a000-000176000000', 'Vérifier si le foret ou le disque chauffe excessivement.', 'Ils doivent être affûtés et strictement adaptés au type de matériau usiné.', 'Suva 67092 — Lames & Disques', 'Affûtage et type', 'Ils doivent être affûtés et strictement adaptés au type de matériau usiné.', false, true);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, critere, base_legale, objet, explications, is_custom, actif) VALUES ('dd000000-0001-4000-a000-00019d000000', NULL, 'aa000000-0000-4000-a000-000056000000', 'bb000000-0001-4000-a000-000177000000', 'Pousser un bois sous la scie.', 'La cape protectrice (Suva B90) doit s''abaisser d''elle-même sur la pièce de bois.', 'Suva 67003 — Scie circulaire table', 'Cape de lame B90', 'La cape protectrice (Suva B90) doit s''abaisser d''elle-même sur la pièce de bois.', false, true);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, critere, base_legale, objet, explications, is_custom, actif) VALUES ('dd000000-0001-4000-a000-00019e000000', NULL, 'aa000000-0000-4000-a000-000056000000', 'bb000000-0001-4000-a000-000178000000', 'Vérifier que le capot de la meuleuse d''angle n''est pas ôté.', 'Les machines doivent conserver tous les dispositifs de protection fournis à l''origine.', 'Suva 67092 — Protection disque', 'Capots meuleuse', 'Les machines doivent conserver tous les dispositifs de protection fournis à l''origine.', false, true);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, critere, base_legale, objet, explications, is_custom, actif) VALUES ('dd000000-0001-4000-a000-00019f000000', NULL, 'aa000000-0000-4000-a000-000056000000', 'bb000000-0001-4000-a000-000179000000', 'Vérifier la fiche et la plaque signalétique de la meuleuse.', 'Exiger la double isolation (symbole double carré) ou une prise de terre à 3 broches.', 'Suva 67092 — Double isolation', 'Classe de protection', 'Exiger la double isolation (symbole double carré) ou une prise de terre à 3 broches.', false, true);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, critere, base_legale, objet, explications, is_custom, actif) VALUES ('dd000000-0001-4000-a000-0001a0000000', NULL, 'aa000000-0000-4000-a000-000056000000', 'bb000000-0001-4000-a000-00017a000000', 'Regarder la fine lame en métal derrière les dents de scie.', 'Obligatoire et doit être réglé près des dents pour éviter le rejet violent du bois.', 'Suva 67003 — Scie circulaire table', 'Couteau diviseur', 'Obligatoire et doit être réglé près des dents pour éviter le rejet violent du bois.', false, true);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, critere, base_legale, objet, explications, is_custom, actif) VALUES ('dd000000-0001-4000-a000-0001a1000000', NULL, 'aa000000-0000-4000-a000-000056000000', 'bb000000-0001-4000-a000-00017b000000', 'Vérifier l''étiquette de marquage et le manuel de l''outil.', 'Pour les achats post-1997, une déclaration CE du fabricant doit être disponible.', 'Suva 67092 — CE', 'Déclaration conformité', 'Pour les achats post-1997, une déclaration CE du fabricant doit être disponible.', false, true);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, critere, base_legale, objet, explications, is_custom, actif) VALUES ('dd000000-0001-4000-a000-0001a2000000', NULL, 'aa000000-0000-4000-a000-000056000000', 'bb000000-0001-4000-a000-00017c000000', 'Vérifier le marquage "RPM" sur le disque abrasif.', 'Le diamètre et la vitesse de rotation max du disque doivent correspondre à la meuleuse.', 'Suva 67092 — Concordance vitesse', 'Disque de meuleuse', 'Le diamètre et la vitesse de rotation max du disque doivent correspondre à la meuleuse.', false, true);
