INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, critere, base_legale, objet, explications, is_custom, actif) VALUES ('dd000000-0001-4000-a000-0001a4000000', NULL, 'aa000000-0000-4000-a000-000056000000', 'bb000000-0001-4000-a000-00017e000000', 'Débrancher/rebrancher la scie en marche à vide pour tester.', 'La machine ne doit pas redémarrer toute seule après une coupure de courant', 'Suva 67003 — Scie circulaire table', 'Interrupteur sécurisé', 'La machine ne doit pas redémarrer toute seule après une coupure de courant', false, true);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, critere, base_legale, objet, explications, is_custom, actif) VALUES ('dd000000-0001-4000-a000-0001a5000000', NULL, 'aa000000-0000-4000-a000-000056000000', 'bb000000-0001-4000-a000-00017f000000', 'Vérifier la scie le soir.', 'Laissée dehors, elle doit être recouverte d''une bâche étanche après le travail', 'Suva 67003 — Scie circulaire table', 'Mise à l''abri pluie', 'Laissée dehors, elle doit être recouverte d''une bâche étanche après le travail', false, true);
