INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, critere, base_legale, objet, explications, is_custom, actif) VALUES ('dd000000-0001-4000-a000-0001a9000000', NULL, 'aa000000-0000-4000-a000-000057000000', 'bb000000-0001-4000-a000-000183000000', 'Contrôler l''ergonomie et la sécurité des cloueuses au gaz/air.', 'Le palpeur de sécurité doit être présent. Les cloueuses de > 2,5 kg nécessitent un anneau de suspension (équilibreur), et celles > 6 kg une poignée supplémentaire.', 'Suva 67141 — Fiche 67141', 'Cloueuses et agrafeuses', 'Le palpeur de sécurité doit être présent. Les cloueuses de > 2,5 kg nécessitent un anneau de suspension (équilibreur), et celles > 6 kg une poignée supplémentaire.', false, true);
