INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, critere, base_legale, objet, explications, is_custom, actif) VALUES ('dd000000-0001-4000-a000-0001ed000000', NULL, 'aa000000-0000-4000-a000-00006b000000', 'bb000000-0001-4000-a000-0001c7000000', 'Contrôler la sécurisation du personnel sur terrain escarpé.', 'Sape interdite. Assurage encordé obligatoire (art. 22-29)', 'OTConst — Art. 107-108', 'Sape et chute de hauteur', 'Sape interdite. Assurage encordé obligatoire (art. 22-29)', false, true);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, critere, base_legale, objet, explications, is_custom, actif) VALUES ('dd000000-0001-4000-a000-0001ee000000', NULL, 'aa000000-0000-4000-a000-00006c000000', 'bb000000-0001-4000-a000-0001c8000000', 'Contrôler le niveau de bruit et le port des protecteurs d''ouïe.', 'Le port est obligatoire dès 85 dB(A) et la zone doit être signalée par un panneau bleu. Des examens audiométriques préventifs doivent être proposés aux moins de 40 ans.', 'Suva 67009 — Fiche 67009', 'Bruit au poste de travail', 'Le port est obligatoire dès 85 dB(A) et la zone doit être signalée par un panneau bleu. Des examens audiométriques préventifs doivent être proposés aux moins de 40 ans.', false, true);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, critere, base_legale, objet, explications, is_custom, actif) VALUES ('dd000000-0001-4000-a000-0001ef000000', NULL, 'aa000000-0000-4000-a000-00006c000000', 'bb000000-0001-4000-a000-0001c9000000', 'Vérifier la formation et le plan de sauvetage.', 'Les travailleurs utilisant un harnais doivent être formés (min. 1 jour). Un plan de sauvetage doit garantir qu''une personne suspendue sera secourue en 20 minutes maximum.', 'Suva 44002 — Fiche 44002', 'EPI Antichute (Harnais)', 'Les travailleurs utilisant un harnais doivent être formés (min. 1 jour). Un plan de sauvetage doit garantir qu''une personne suspendue sera secourue en 20 minutes maximum.', false, true);
INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, critere, base_legale, objet, explications, is_custom, actif) VALUES ('dd000000-0001-4000-a000-0001f0000000', NULL, 'aa000000-0000-4000-a000-00006c000000', 'bb000000-0001-4000-a000-0001ca000000', 'Contrôler les mesures de protection contre les produits chimiques.', 'Le contact cutané avec des résines (époxy, PU), ciments ou solvants peut causer des eczémas graves. L''utilisation de gants adaptés et de crèmes de soin est requise', 'Suva 44074 — Fiche 44074', 'Protection de la peau', 'Le contact cutané avec des résines (époxy, PU), ciments ou solvants peut causer des eczémas graves. L''utilisation de gants adaptés et de crèmes de soin est requise', false, true);
