INSERT INTO points_controle (id, phase_id, categorie_id, theme_id, intitule, critere, base_legale, objet, explications, is_custom, actif) VALUES ('dd000000-0002-4000-a000-000215000000', NULL, 'aa000000-0000-4000-a000-000079000000', 'bb000000-0001-4000-a000-0001ef000000', 'Évaluer la pente du toit et la hauteur de chute pour exiger l''échafaudage', 'Exigé si bas du toit ≥ 3m ET pente > 20% (métal/plastique) ou > 40% (tuile/ardoise)', 'RPAC — Art. 22', 'Échafaudages de toit', 'Exigé si bas du toit ≥ 3m ET pente > 20% (métal/plastique) ou > 40% (tuile/ardoise)', false, true);
